1	/* Arumed Apps design tokens
2	 * Single source of truth for colors, spacing, and surfaces.
3	 * Mirrors the palette established across the static HTML prototypes. */
4	
5	:root {
6	  /* Brand (primary) — navy-premium: biru DITAHAN (hemat), navy untuk struktur */
7	  --gd: #103a68;   /* navy pekat — judul, header, btn-primary (mahal, institusional) */
8	  --gm: #18548f;   /* navy sedang — hover */
9	  --ga: #1d63b3;   /* AKSEN biru (lebih dalam & kalem, tidak ngejreng) — tombol/link/aktif */
10	  --gl: #eef3f9;   /* tint sangat halus — bg item aktif/hover (tidak 'menyala') */
11	  --gb: #e3e7ee;   /* border halus abu-biru netral */
12	
13	  /* Accent — cyan logo (highlight kecil saja, jangan dominan) */
14	  --lm: #3fb5e8;
15	  --ld: #0284c7;
16	
17	  /* Backgrounds & surfaces — putih bersih + abu netral lembut (premium, tidak dingin) */
18	  --bg: #f6f8fb;   /* page bg — abu-cool nyaris putih */
19	  --bp: #fbfcfe;   /* panel */
20	  --bc: #ffffff;   /* kartu/surface utama — putih bersih */
21	  --bs: #f9fafc;   /* surface lembut */
22	  --bi: #f3f5f8;   /* surface info / baris zebra (abu netral lembut) */
23	
24	  /* Text — hitam/abu NETRAL (tanpa undertone biru), kontras tinggi & bersih */
25	  --td: #1a1a1a;   /* teks utama / judul — hitam pekat */
26	  --tm: #333333;   /* teks sekunder — abu-hitam */
27	  --tu: #6b7280;   /* muted — abu netral (aksesibel) */
28	  --th: #9ca3af;   /* hint — abu netral terang */
29	
30	  /* Semantic — success */
31	  --sb: #f0fdf4;
32	  --sbd: #86efac;
33	  --st: #15803d;
34	
35	  /* Semantic — error */
36	  --eb: #fef2f2;
37	  --ebd: #fca5a5;
38	  --et: #dc2626;
39	
40	  /* Semantic — warning */
41	  --wb: #fffbeb;
42	  --wbd: #fcd34d;
43	  --wt: #b45309;
44	
45	  /* Semantic — info */
46	  --ib: #eff6ff;
47	  --ibd: #93c5fd;
48	  --it: #1d4ed8;
49	
50	  /* Semantic — purple (ASN/special) */
51	  --pb: #fdf4ff;
52	  --pbd: #d946ef;
53	  --pt: #7e22ce;
54	
55	  /* Layout */
56	  --sidebar: 240px;
57	
58	  /* Typography — Inter (body/UI) + Space Grotesk (heading kontras) + JetBrains Mono */
59	  --font-sans: 'Inter', system-ui, -apple-system, 'Segoe UI', sans-serif;
60	  --font-display: 'Space Grotesk', 'Inter', system-ui, sans-serif;
61	  --font-mono: 'JetBrains Mono', 'SF Mono', 'Consolas', monospace;
62	}
63

1	*,
2	*::before,
3	*::after {
4	  box-sizing: border-box;
5	  margin: 0;
6	  padding: 0;
7	}
8	
9	html,
10	body {
11	  height: 100%;
12	  background: var(--bg);
13	  font-family: var(--font-sans);
14	  color: var(--td);
15	  -webkit-font-smoothing: antialiased;
16	  -moz-osx-font-smoothing: grayscale;
17	  text-rendering: optimizeLegibility;
18	}
19	
20	body {
21	  min-width: 1280px;
22	}
23	
24	a {
25	  color: inherit;
26	  text-decoration: none;
27	}
28	
29	button {
30	  font-family: inherit;
31	}
32	
33	/* Universal scrollbar styling */
34	::-webkit-scrollbar {
35	  width: 6px;
36	  height: 6px;
37	}
38	::-webkit-scrollbar-thumb {
39	  background: var(--gb);
40	  border-radius: 3px;
41	}
42	::-webkit-scrollbar-thumb:hover {
43	  background: var(--th);
44	}
45	
46	@keyframes spin {
47	  to {
48	    transform: rotate(360deg);
49	  }
50	}
51	
52	@keyframes blink {
53	  0%, 100% { opacity: 1; }
54	  50% { opacity: 0.4; }
55	}
56	
57	@keyframes ripple {
58	  0% { transform: scale(1); opacity: 0.5; }
59	  100% { transform: scale(2.6); opacity: 0; }
60	}
