4	import { useAuthStore } from '@/stores/auth'
5	
6	const route = useRoute()
7	const auth = useAuthStore()
8	const now = ref(new Date())
9	let timer = null
10	
11	onMounted(() => {
12	  timer = setInterval(() => (now.value = new Date()), 1000)
13	})
14	onUnmounted(() => clearInterval(timer))
15	
16	const clock = computed(() =>
17	  now.value.toLocaleTimeString('id-ID', { hour: '2-digit', minute: '2-digit', second: '2-digit' }),
18	)
19	
20	const title = computed(() => route.meta?.title ?? 'Arumed Apps')
21	
22	// ─── Identitas dokter (hanya akun dokter) ───────────────────────────────────
23	// Data nama + SIP dari akun login (Data Pengguna → employee). Ditampilkan inline
24	// di topbar (tanpa card), tidak hanya di RME Dokter.
25	const isDoctorAccount = computed(() => {
26	  const prof = (auth.user?.employee?.profession ?? '').toLowerCase()
27	  const role = (auth.user?.role?.name ?? '').toLowerCase()
28	  const rdisp = (auth.user?.role?.display_name ?? '').toLowerCase()
29	  return prof.includes('dokter') || role.includes('dokter') || rdisp.includes('dokter')
30	})
31	const doctorName = computed(() => {
32	  const n = auth.user?.employee?.name ?? auth.user?.name ?? ''
33	  if (!n) return 'Dokter'
34	  return /^dr\.?\s/i.test(n) ? n : `dr. ${n}`
35	})
36	const doctorSip = computed(() => auth.user?.employee?.sip ?? '')
37	</script>
